window.QUESTIONS_D3 = [
{"id":"RW-D3-01","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.2","stem":"A hospital wants a new patient portal because &quot;patients complain communication is hard.&quot; Before issuing an RFP, what should the project team do FIRST?","opts":[{"l":"A","c":false,"t":"Select the portal with the most mobile features"},{"l":"B","c":true,"t":"Conduct needs analysis and current-state workflow assessment"},{"l":"C","c":false,"t":"Negotiate an SLA"},{"l":"D","c":false,"t":"Begin user acceptance testing"}],"rat":"Solution selection must begin with understanding the actual problem, current-state gaps, stakeholders, and functional requirements — not technology selection."},
{"id":"RW-D3-02","domain":2,"cog":"AN","correct":"B","task":"Task 3.A.2","stem":"During scheduling system planning, clinicians request 50 enhancements. The go-live date is fixed because of a regulatory deadline. What should the project manager do?","opts":[{"l":"A","c":false,"t":"Add every request to preserve goodwill"},{"l":"B","c":true,"t":"Prioritize requirements using a method such as MoSCoW and document deferrals"},{"l":"C","c":false,"t":"Reject all clinical requests"},{"l":"D","c":false,"t":"Skip requirements validation"}],"rat":"MoSCoW (Must / Should / Could / Won&#x27;t) separates go-live-critical requirements from items that can be deferred to a later phase without delaying the deadline."},
{"id":"RW-D3-13","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.1","stem":"A health system is building a new patient portal with frequently changing user requirements and clinician feedback cycles planned every two weeks. Which SDLC model is MOST appropriate?","opts":[{"l":"A","c":false,"t":"Waterfall, because it provides clear phase gates and formal documentation"},{"l":"B","c":true,"t":"Agile, because it supports iterative delivery and continuous stakeholder feedback"},{"l":"C","c":false,"t":"Spiral, because it is designed for low-risk, single-phase deliverables"},{"l":"D","c":false,"t":"RAD, because portals do not require testing cycles"}],"rat":"Agile&#x27;s iterative sprints and continuous feedback loops are suited to projects where requirements evolve and users validate increments throughout development."},
{"id":"RW-D3-28","domain":2,"cog":"AN","correct":"B","task":"Task 3.A.1, 3.A.2","stem":"An informatics director reviews a project charter for a new scheduling system and notices it lists the project objectives, sponsor name, and budget, but does not define the project scope or list key stakeholders. What SDLC artifact should be updated NEXT?","opts":[{"l":"A","c":false,"t":"Risk register"},{"l":"B","c":true,"t":"The project charter itself — to add scope boundaries and stakeholder list"},{"l":"C","c":false,"t":"SLA with the scheduling vendor"},{"l":"D","c":false,"t":"Training plan"}],"rat":"A project charter is the formal authorization document; it must define scope, objectives, sponsor, stakeholders, and budget before planning proceeds."},
{"id":"RW-D3-14","domain":2,"cog":"RE","correct":"C","task":"Task 3.A.3","stem":"A hospital quality team is reducing CAUTI infections. They quantify baseline infection rates, identify contributing root causes through data analysis, implement catheter care protocol changes, and establish ongoing monitoring dashboards. This structured methodology is:","opts":[{"l":"A","c":false,"t":"PDCA"},{"l":"B","c":false,"t":"ADKAR"},{"l":"C","c":true,"t":"DMAIC"},{"l":"D","c":false,"t":"Kotter&#x27;s 8-Step Model"}],"rat":"DMAIC (Define, Measure, Analyze, Improve, Control) is the Six Sigma process improvement framework. PDCA is similar but uses lighter statistical rigor."},
{"id":"RW-D3-26","domain":2,"cog":"AN","correct":"C","task":"Task 3.A.3","stem":"A clinical informatics team observes that a 12-step medication ordering workflow contains only 4 steps that directly contribute to patient safety verification; the other 8 involve re-entering data, redundant approvals, and searching for duplicate information. Which improvement approach BEST identifies and eliminates these non-value-added steps?","opts":[{"l":"A","c":false,"t":"DMAIC"},{"l":"B","c":false,"t":"PDCA"},{"l":"C","c":true,"t":"Lean / value stream mapping"},{"l":"D","c":false,"t":"Fishbone analysis"}],"rat":"Lean focuses on eliminating waste (non-value-added steps); value stream mapping visualizes the entire workflow to surface waste and inefficiency."},
{"id":"RW-D3-29","domain":2,"cog":"AP","correct":"C","task":"Task 3.A.3","stem":"A quality improvement team in a surgical department repeatedly asks &quot;why&quot; to trace a high post-operative complication rate from its observable symptom back to a root operational cause. After five iterations, they identify inadequate surgeon briefing as the root cause. Which technique is being applied?","opts":[{"l":"A","c":false,"t":"PDCA"},{"l":"B","c":false,"t":"Affinity diagram"},{"l":"C","c":true,"t":"5 Whys"},{"l":"D","c":false,"t":"SIPOC"}],"rat":"The 5 Whys technique iteratively asks &quot;why?&quot; to drill through symptoms to the underlying root cause. It is a Lean/Six Sigma root cause analysis tool."},
{"id":"RW-D3-15","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.4","stem":"An implementation team is mapping the hospital discharge process and needs to show which staff role — case manager, physician, nurse, or social worker — performs each step and where handoffs occur. The MOST appropriate tool is:","opts":[{"l":"A","c":false,"t":"Fishbone diagram"},{"l":"B","c":true,"t":"Swim lane diagram"},{"l":"C","c":false,"t":"Run chart"},{"l":"D","c":false,"t":"SIPOC diagram"}],"rat":"Swim lane diagrams assign each role its own lane and show exactly who performs each step and where cross-role handoffs occur."},
{"id":"RW-D3-41","domain":2,"cog":"AP","correct":"C","task":"Task 3.A.4","stem":"A project team is scoping a new prior authorization workflow and needs a high-level view showing the suppliers, inputs, key process steps, outputs, and customers before doing detailed process mapping. The MOST appropriate tool is:","opts":[{"l":"A","c":false,"t":"Swim lane diagram"},{"l":"B","c":false,"t":"Fishbone diagram"},{"l":"C","c":true,"t":"SIPOC diagram"},{"l":"D","c":false,"t":"Control chart"}],"rat":"SIPOC (Supplier-Input-Process-Output-Customer) is a high-level scoping tool used at the start of a process improvement initiative to define boundaries before detailed mapping."},
{"id":"RW-D3-42","domain":2,"cog":"AP","correct":"C","task":"Task 3.A.4","stem":"After a series of medication errors in the ICU, the patient safety officer wants to visualize all potential contributing causes organized by categories such as People, Process, Technology, Environment, and Policy. The MOST appropriate tool is:","opts":[{"l":"A","c":false,"t":"Swim lane diagram"},{"l":"B","c":false,"t":"SIPOC"},{"l":"C","c":true,"t":"Fishbone (Ishikawa) diagram"},{"l":"D","c":false,"t":"Value stream map"}],"rat":"The Fishbone (Cause-and-Effect / Ishikawa) diagram organizes potential root causes by category (often the 6Ms: Man, Machine, Method, Material, Measurement, Mother Nature), making it ideal for structured root cause analysis."},
{"id":"RW-D3-03","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.1, 3.A.10","stem":"After reviewing RFP responses for a new EHR, two vendors remain. What selection activity should happen NEXT?","opts":[{"l":"A","c":false,"t":"Execute the cheapest contract"},{"l":"B","c":true,"t":"Conduct scripted demonstrations using real organizational scenarios"},{"l":"C","c":false,"t":"Begin production data migration"},{"l":"D","c":false,"t":"Close the project charter"}],"rat":"Scenario-based demonstrations test workflow fit against actual organizational needs — beyond what written proposals can convey."},
{"id":"RW-D3-31","domain":2,"cog":"RE","correct":"C","task":"Task 3.A.10","stem":"An organization sends a document to EHR vendors requesting capabilities information, implementation approach, and rough pricing — but is not yet ready to commit to a formal selection. This document is BEST described as:","opts":[{"l":"A","c":false,"t":"Request for Proposal (RFP)"},{"l":"B","c":false,"t":"Statement of Work (SOW)"},{"l":"C","c":true,"t":"Request for Information (RFI)"},{"l":"D","c":false,"t":"Non-Disclosure Agreement (NDA)"}],"rat":"An RFI is an early-stage inquiry to gather vendor capabilities without a commitment to purchase; an RFP is the formal solicitation for a detailed proposal and pricing."},
{"id":"RW-D3-32","domain":2,"cog":"RE","correct":"C","task":"Task 3.A.10","stem":"Before sharing confidential clinical workflow documentation with a potential integration partner during early-stage discussions, the organization should require the partner to sign:","opts":[{"l":"A","c":false,"t":"A Statement of Work"},{"l":"B","c":false,"t":"A Service Level Agreement"},{"l":"C","c":true,"t":"A Non-Disclosure Agreement"},{"l":"D","c":false,"t":"A Business Associate Agreement"}],"rat":"An NDA (Non-Disclosure Agreement) legally protects confidential information shared between parties during exploratory or pre-contract discussions. A BAA is required specifically when a vendor will access PHI."},
{"id":"RW-D3-33","domain":2,"cog":"AP","correct":"C","task":"Task 3.A.10","stem":"A health system signs a contract with a consulting firm for EHR optimization services. The document that specifically defines the scope of work, deliverables, timeline, and payment terms for this engagement is:","opts":[{"l":"A","c":false,"t":"SLA (Service Level Agreement)"},{"l":"B","c":false,"t":"NDA (Non-Disclosure Agreement)"},{"l":"C","c":true,"t":"SOW (Statement of Work)"},{"l":"D","c":false,"t":"RFQ (Request for Quote)"}],"rat":"An SOW defines what will be done, when, and at what cost for a specific engagement. An SLA defines performance standards (uptime, response times) rather than project scope."},
{"id":"RW-D3-10","domain":2,"cog":"AN","correct":"B","task":"Task 3.B.1, 3.E.2","stem":"A vulnerability scan finds unsupported operating systems on connected infusion pumps. What is the BEST next step?","opts":[{"l":"A","c":false,"t":"Ignore the finding because the devices are clinical"},{"l":"B","c":true,"t":"Perform risk assessment and coordinate mitigation such as patching, segmentation, or replacement"},{"l":"C","c":false,"t":"Disconnect every pump immediately without clinical planning"},{"l":"D","c":false,"t":"Ask nurses to stop using smart pump libraries"}],"rat":"Medical device security requires risk-based mitigation that balances cybersecurity risk reduction with continued safe clinical operations."},
{"id":"RW-D3-17","domain":2,"cog":"AP","correct":"C","task":"Task 3.B.1","stem":"A hospital wants to allow a third-party patient-facing app to securely query the EHR for a patient&#x27;s medication list using the patient&#x27;s existing EHR credentials. The MOST appropriate standard is:","opts":[{"l":"A","c":false,"t":"Direct Protocol"},{"l":"B","c":false,"t":"HL7 v2.x"},{"l":"C","c":true,"t":"SMART on FHIR"},{"l":"D","c":false,"t":"DICOM"}],"rat":"SMART on FHIR enables authorized third-party app integration with EHRs using OAuth 2.0 authentication and FHIR resource queries."},
{"id":"RW-D3-37","domain":2,"cog":"AN","correct":"B","task":"Task 3.A.6, 3.B.1","stem":"An organization is evaluating whether to develop an in-house clinical analytics platform, purchase a commercial solution, or partner with a specialty analytics firm. The team identifies that the core analytics functionality is a commodity available from multiple mature vendors, while IT resources are constrained. What should guide the build-vs-buy-vs-partner decision in this context?","opts":[{"l":"A","c":false,"t":"Build in-house because proprietary solutions better protect data"},{"l":"B","c":true,"t":"Buy a commercial solution because the functionality is commodity and internal resources are limited"},{"l":"C","c":false,"t":"Partner regardless because partnerships always provide better customization"},{"l":"D","c":false,"t":"Defer the decision until the next budget cycle"}],"rat":"Build is appropriate for unique competitive capabilities; buy suits commodity needs where vendors have mature products; partner suits specialized expertise gaps. Limited resources + commodity function = buy."},
{"id":"RW-D3-12","domain":2,"cog":"AP","correct":"A","task":"Task 3.B.2","stem":"A hospital wants to verify that an EHR product qualifies for federal health IT certification criteria used in CMS Promoting Interoperability programs. Which organization is MOST relevant?","opts":[{"l":"A","c":true,"t":"ONC"},{"l":"B","c":false,"t":"The Joint Commission"},{"l":"C","c":false,"t":"CARF"},{"l":"D","c":false,"t":"Local fire marshal"}],"rat":"ONC (Office of the National Coordinator for Health IT) manages the federal health IT certification program used to qualify for CMS Promoting Interoperability incentives."},
{"id":"RW-D3-07","domain":2,"cog":"AP","correct":"A","task":"Task 3.B.4","stem":"An EHR outage begins during a storm. Clinicians need to keep documenting care while IT restores systems. Which plan guides the manual clinical workflow?","opts":[{"l":"A","c":true,"t":"Business continuity plan and downtime procedures"},{"l":"B","c":false,"t":"Vendor marketing plan"},{"l":"C","c":false,"t":"Capital budget"},{"l":"D","c":false,"t":"Data dictionary"}],"rat":"The BCP and associated downtime procedures keep essential clinical operations running during a disruption; the DRP guides IT system restoration."},
{"id":"RW-D3-16","domain":2,"cog":"AP","correct":"B","task":"Task 3.B.4","stem":"Clinical leaders state they can tolerate a maximum of 2 hours of system downtime and can afford to lose up to 30 minutes of transaction data if the lab results system fails. The correct recovery targets are:","opts":[{"l":"A","c":false,"t":"RTO = 30 minutes; RPO = 2 hours"},{"l":"B","c":true,"t":"RTO = 2 hours; RPO = 30 minutes"},{"l":"C","c":false,"t":"RTO = RPO = 2 hours"},{"l":"D","c":false,"t":"RTO = 0; RPO = 4 hours"}],"rat":"RTO = Recovery Time Objective (max tolerable downtime = 2 hours); RPO = Recovery Point Objective (max tolerable data loss expressed as time = 30 minutes)."},
{"id":"RW-D3-25","domain":2,"cog":"AP","correct":"C","task":"Task 3.B.4","stem":"A health system&#x27;s primary data center is destroyed in a flood. Clinical systems must be restored with the shortest possible recovery time. Which disaster recovery site type enables the fastest recovery?","opts":[{"l":"A","c":false,"t":"Cold site"},{"l":"B","c":false,"t":"Warm site"},{"l":"C","c":true,"t":"Hot site"},{"l":"D","c":false,"t":"Remote offsite tape backup library"}],"rat":"A hot site is fully operational with current data replication, enabling near-immediate failover and the lowest possible RTO."},
{"id":"RW-D3-09","domain":2,"cog":"AN","correct":"A","task":"Task 3.B.6","stem":"The EHR defines discharge time as &quot;order entered,&quot; while finance defines it as &quot;patient left bed.&quot; Reports conflict. Which governance artifact should be created or updated?","opts":[{"l":"A","c":true,"t":"Data dictionary with accountable data stewards"},{"l":"B","c":false,"t":"Vendor invoice"},{"l":"C","c":false,"t":"Wireless heat map"},{"l":"D","c":false,"t":"Training attendance sheet"}],"rat":"A data dictionary defines data elements, their authoritative meaning, valid values, and the responsible data steward — the standard data governance resolution for conflicting definitions."},
{"id":"RW-D3-38","domain":2,"cog":"AP","correct":"C","task":"Task 3.B.6, 3.E.6","stem":"A health system establishes a policy requiring that patient records be retained for a minimum of 10 years after the last date of service, and that records older than 10 years be securely archived or destroyed per approved protocols. This policy is an example of:","opts":[{"l":"A","c":false,"t":"Data dictionary management"},{"l":"B","c":false,"t":"Master data management"},{"l":"C","c":true,"t":"Data retention and lifecycle management"},{"l":"D","c":false,"t":"Access recertification"}],"rat":"Data lifecycle management defines policies for each stage of data from creation through retention and secure destruction, ensuring regulatory compliance and minimizing liability."},
{"id":"RW-D3-23","domain":2,"cog":"AP","correct":"C","task":"Task 3.C.1","stem":"After reviewing written proposals and conducting vendor demonstrations, the EHR selection committee wants to see how a reference organization&#x27;s clinical staff actually interact with the system in daily operations. This activity is called:","opts":[{"l":"A","c":false,"t":"Reference check"},{"l":"B","c":false,"t":"Proof of concept"},{"l":"C","c":true,"t":"Site visit"},{"l":"D","c":false,"t":"User acceptance testing"}],"rat":"Site visits allow the selection team to observe real-world workflow integration and end-user experience at a live reference customer using the proposed system."},
{"id":"RW-D3-04","domain":2,"cog":"AN","correct":"B","task":"Task 3.C.4","stem":"Midway through an EHR implementation, the cardiology department requests a major new module outside the approved scope. What is the BEST response?","opts":[{"l":"A","c":false,"t":"Add it immediately because cardiology is influential"},{"l":"B","c":true,"t":"Route it through formal change control to assess scope, schedule, budget, and risk"},{"l":"C","c":false,"t":"Ignore the request"},{"l":"D","c":false,"t":"Stop all build work until cardiology is satisfied"}],"rat":"Change control protects the project baseline and ensures all scope changes are evaluated transparently before approval."},
{"id":"RW-D3-18","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.3","stem":"A hospital system needs to train 5,000 end users across 8 facilities before an EHR go-live. The vendor cannot provide direct classroom training to all users. The MOST scalable training strategy is:","opts":[{"l":"A","c":false,"t":"Hire enough contract trainers to reach all 5,000 users simultaneously"},{"l":"B","c":true,"t":"Train-the-Trainer — build internal expert trainers who then train their department peers"},{"l":"C","c":false,"t":"Provide no pre-go-live training and rely solely on at-the-elbow support"},{"l":"D","c":false,"t":"Send all users to the vendor&#x27;s national training center"}],"rat":"Train-the-Trainer multiplies the organization&#x27;s training capacity by creating a layer of internal expert trainers who scale to the full user base."},
{"id":"RW-D3-24","domain":2,"cog":"AN","correct":"B","task":"Task 3.C.4","stem":"During the final month of an EHR build, the CMO requests adding a full telehealth module not included in the original scope. The project team&#x27;s BEST response is:","opts":[{"l":"A","c":false,"t":"Add it immediately because the CMO has authority"},{"l":"B","c":true,"t":"Document the request, evaluate impact on scope, schedule, and budget, then route through change control"},{"l":"C","c":false,"t":"Postpone all other build work until the telehealth module is complete"},{"l":"D","c":false,"t":"Reject the request without evaluation"}],"rat":"All scope changes, regardless of requester authority, must go through formal change control to assess and document the impact on the project baseline."},
{"id":"RW-D3-36","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.2","stem":"A major EHR software update is scheduled to deploy to production next Tuesday. The change management team needs to review the update&#x27;s risk, testing results, and potential impact on clinical workflows before approving the deployment. Which governance body performs this review?","opts":[{"l":"A","c":false,"t":"The CDS governance committee"},{"l":"B","c":true,"t":"The Change Advisory Board (CAB)"},{"l":"C","c":false,"t":"The data governance council"},{"l":"D","c":false,"t":"The vendor&#x27;s project management office"}],"rat":"The Change Advisory Board reviews, approves, and schedules significant system changes, assessing risk and impact before production deployment."},
{"id":"RW-D3-05","domain":2,"cog":"AP","correct":"B","task":"Task 3.D.1","stem":"The implementation team is testing whether medication orders entered in CPOE arrive correctly in the pharmacy system and return verification status to the eMAR. What type of testing is this?","opts":[{"l":"A","c":false,"t":"Unit testing"},{"l":"B","c":true,"t":"Integration testing"},{"l":"C","c":false,"t":"Acceptance testing only"},{"l":"D","c":false,"t":"Benefits realization"}],"rat":"Integration testing validates data flow and behavior between two or more connected systems (CPOE → Pharmacy → eMAR)."},
{"id":"RW-D3-06","domain":2,"cog":"AN","correct":"B","task":"Task 3.D.1, 3.D.3","stem":"One week before go-live, UAT shows that nurses cannot document a required discharge education step for pediatric patients. What should the project team do?","opts":[{"l":"A","c":false,"t":"Go live anyway and fix it later"},{"l":"B","c":true,"t":"Treat it as a critical defect, remediate, retest, and reassess go-live readiness"},{"l":"C","c":false,"t":"Delete the discharge education requirement"},{"l":"D","c":false,"t":"Ask nurses to document in free text without tracking"}],"rat":"UAT exists to confirm workflow and requirement fit before go-live; patient care and compliance gaps identified in UAT must be resolved before cutover."},
{"id":"RW-D3-19","domain":2,"cog":"AN","correct":"B","task":"Task 3.D.1","stem":"An implementation team has completed unit testing and integration testing for a new ED tracking system. What type of testing should occur NEXT before User Acceptance Testing?","opts":[{"l":"A","c":false,"t":"Stress testing only"},{"l":"B","c":true,"t":"System testing, to validate end-to-end functionality in a production-like environment"},{"l":"C","c":false,"t":"Regression testing of the existing system"},{"l":"D","c":false,"t":"Acceptance testing to obtain contractual sign-off"}],"rat":"The correct sequence is: unit → integration → system → UAT → acceptance. System testing validates the complete system before clinical end users conduct UAT."},
{"id":"RW-D3-11","domain":2,"cog":"AP","correct":"A","task":"Task 3.D.4","stem":"Six months after a revenue cycle system go-live, the CFO asks whether the promised reduction in days in A/R happened. What activity is this?","opts":[{"l":"A","c":true,"t":"Benefits realization evaluation"},{"l":"B","c":false,"t":"Unit testing"},{"l":"C","c":false,"t":"RFI development"},{"l":"D","c":false,"t":"Downtime drill"}],"rat":"Benefits realization compares actual post-implementation outcomes against projected benefits defined before the project began."},
{"id":"RW-D3-34","domain":2,"cog":"AP","correct":"C","task":"Task 3.D.1","stem":"After deploying a patch to the EHR&#x27;s medication order entry module, the testing team runs a suite of previously validated test cases to ensure the patch did not break existing functionality elsewhere in the system. This type of testing is:","opts":[{"l":"A","c":false,"t":"UAT"},{"l":"B","c":false,"t":"Stress testing"},{"l":"C","c":true,"t":"Regression testing"},{"l":"D","c":false,"t":"Integration testing"}],"rat":"Regression testing verifies that new changes (patches, upgrades) have not broken previously working functionality in the system."},
{"id":"RW-D3-35","domain":2,"cog":"AP","correct":"C","task":"Task 3.D.1","stem":"Before go-live, the testing team simulates 500 simultaneous users logging into the EHR and performing high-volume order entry to determine if the system can handle peak clinical load. This type of testing is:","opts":[{"l":"A","c":false,"t":"Integration testing"},{"l":"B","c":false,"t":"Regression testing"},{"l":"C","c":true,"t":"Stress / load testing"},{"l":"D","c":false,"t":"User acceptance testing"}],"rat":"Stress and load testing evaluate system performance under high-volume conditions — ensuring the infrastructure and application will not degrade during peak operational use."},
{"id":"RW-D3-08","domain":2,"cog":"AP","correct":"B","task":"Task 3.E.3","stem":"HR notifies IT that a billing employee with broad EHR access was terminated immediately. What should happen FIRST?","opts":[{"l":"A","c":false,"t":"Wait for the next monthly access review"},{"l":"B","c":true,"t":"Immediately revoke system access credentials"},{"l":"C","c":false,"t":"Notify all patients"},{"l":"D","c":false,"t":"Delete all audit logs"}],"rat":"Termination procedures require immediate access revocation to protect confidentiality; delayed revocation creates ongoing risk of unauthorized data access."},
{"id":"RW-D3-20","domain":2,"cog":"AP","correct":"C","task":"Task 3.E.1","stem":"A ransomware attack encrypts all patient records. Backups exist but systems are completely inaccessible to clinicians for 14 hours. Which component of the CIA triad was MOST directly violated?","opts":[{"l":"A","c":false,"t":"Confidentiality"},{"l":"B","c":false,"t":"Integrity"},{"l":"C","c":true,"t":"Availability"},{"l":"D","c":false,"t":"Authentication"}],"rat":"Availability means systems and data are accessible when needed by authorized users. Ransomware denies that access, directly violating availability."},
{"id":"RW-D3-21","domain":2,"cog":"AN","correct":"B","task":"Task 3.E.3","stem":"A patient registrar responsible for insurance verification is found to have full access to clinical documentation, medication history, and surgical notes. Which access control principle was NOT enforced?","opts":[{"l":"A","c":false,"t":"Role-based access control"},{"l":"B","c":true,"t":"Least privilege / minimum necessary"},{"l":"C","c":false,"t":"Multi-factor authentication"},{"l":"D","c":false,"t":"Audit logging"}],"rat":"Least privilege requires that users receive only the access rights required for their specific job function — not broader access based on general role membership."},
{"id":"RW-D3-22","domain":2,"cog":"AP","correct":"C","task":"Task 3.E.6","stem":"A hospital is decommissioning hard drives from workstations that previously stored ePHI. Before disposing of the drives, the MOST appropriate action is:","opts":[{"l":"A","c":false,"t":"Delete files using the Windows recycle bin"},{"l":"B","c":false,"t":"Reformat the drives using standard OS tools"},{"l":"C","c":true,"t":"Perform secure media destruction or cryptographic erasure per NIST 800-88"},{"l":"D","c":false,"t":"Return the drives to the vendor without erasure"}],"rat":"PHI on decommissioned media must be permanently and verifiably destroyed per HIPAA and NIST SP 800-88; standard deletion tools leave data recoverable."},
{"id":"RW-D3-27","domain":2,"cog":"AP","correct":"B","task":"Task 3.E.4, 1.B.2","stem":"An audit finds that employees&#x27; personal smartphones are connecting to the same internal Wi-Fi network used by clinical applications and the EHR. The MOST appropriate technical control is:","opts":[{"l":"A","c":false,"t":"Ban all personal devices from the facility"},{"l":"B","c":true,"t":"Implement a guest/BYOD VLAN that is logically segmented from the clinical network"},{"l":"C","c":false,"t":"Require employees to sign an acceptable use policy only"},{"l":"D","c":false,"t":"Install endpoint security software on all personal devices"}],"rat":"Network segmentation (VLAN) is a technical safeguard that isolates personal devices from clinical systems, reducing risk without banning devices or relying on policy alone."},
{"id":"RW-D3-39","domain":2,"cog":"RE","correct":"C","task":"Task 3.E.4","stem":"Under the HIPAA Security Rule, which safeguard category includes workforce security training, a sanctions policy for violations, and the annual security risk assessment?","opts":[{"l":"A","c":false,"t":"Physical safeguards"},{"l":"B","c":false,"t":"Technical safeguards"},{"l":"C","c":true,"t":"Administrative safeguards"},{"l":"D","c":false,"t":"Operational safeguards"}],"rat":"Administrative safeguards include policies, procedures, workforce training, risk assessments, and sanction policies. Physical = facility/device controls; Technical = encryption, audit logs, auto-logoff."},
{"id":"RW-D3-40","domain":2,"cog":"AP","correct":"B","task":"Task 3.E.2, 3.E.7","stem":"A hospital&#x27;s IT security team hires an external firm to perform an authorized simulated attack on the clinical network — probing for exploitable vulnerabilities in applications, infrastructure, and configurations. This activity is called:","opts":[{"l":"A","c":false,"t":"Vulnerability scanning"},{"l":"B","c":true,"t":"Penetration testing"},{"l":"C","c":false,"t":"SIEM log analysis"},{"l":"D","c":false,"t":"Tabletop exercise"}],"rat":"Penetration testing (ethical hacking) is an authorized, simulated attack to find exploitable vulnerabilities. Vulnerability scanning is automated and finds known vulnerabilities but does not actively exploit them."},
{"id":"RW-D3-43","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.1","stem":"A government hospital must implement a new billing system with fixed regulatory requirements and a hard go-live deadline mandated by CMS. Scope is locked and sign-off is required at each phase before proceeding. Which SDLC model BEST fits this context?","opts":[{"l":"A","c":false,"t":"Agile, because iterative feedback is always preferred"},{"l":"B","c":true,"t":"Waterfall, because requirements are fixed and phase gates are required"},{"l":"C","c":false,"t":"Spiral, because there is high risk and uncertainty"},{"l":"D","c":false,"t":"RAD, because the deadline is tight"}],"rat":"Waterfall is appropriate when requirements are fully defined upfront, scope is locked, and formal phase-gate approvals are required — common in regulated government IT projects."},
{"id":"RW-D3-44","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.2","stem":"A project team compares the current state of the patient scheduling process (inconsistent data, paper forms, 3-day wait for appointments) against the desired future state (real-time online booking, 24-hour access, zero paper) and documents all deficiencies. This activity is called:","opts":[{"l":"A","c":false,"t":"Requirements testing"},{"l":"B","c":true,"t":"Gap analysis"},{"l":"C","c":false,"t":"Unit testing"},{"l":"D","c":false,"t":"Stakeholder interview only"}],"rat":"Gap analysis compares the current state (what is) against the desired future state (what should be) and documents the gap — a core step in project planning and needs assessment."},
{"id":"RW-D3-45","domain":2,"cog":"RE","correct":"B","task":"Task 3.A.2","stem":"In a RACI matrix, the person assigned &quot;R&quot; (Responsible) for a task is:","opts":[{"l":"A","c":false,"t":"The single owner ultimately answerable for the outcome"},{"l":"B","c":true,"t":"The person or persons who perform the actual work"},{"l":"C","c":false,"t":"The stakeholder who must approve the deliverable"},{"l":"D","c":false,"t":"The parties who receive status updates only"}],"rat":"Responsible = those who do the work. Accountable = the single owner answerable for the outcome. Consulted = provide input. Informed = receive updates."},
{"id":"RW-D3-46","domain":2,"cog":"AP","correct":"C","task":"Task 3.A.2","stem":"A project manager creates a hierarchical decomposition of all the work needed to complete an EHR implementation — breaking the project into phases, then deliverables, then individual work packages. This planning tool is called:","opts":[{"l":"A","c":false,"t":"RACI matrix"},{"l":"B","c":false,"t":"Risk register"},{"l":"C","c":true,"t":"Work Breakdown Structure (WBS)"},{"l":"D","c":false,"t":"Swim lane diagram"}],"rat":"A WBS decomposes the total project scope into smaller, manageable components (work packages), enabling accurate scheduling, resource assignment, and cost estimation."},
{"id":"RW-D3-47","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.3","stem":"A nursing unit wants to test a new structured hand-off communication process before rolling it out hospital-wide. Using PDCA, what is the correct FIRST action after developing the change?","opts":[{"l":"A","c":false,"t":"Control by publishing the new policy organization-wide"},{"l":"B","c":true,"t":"Do — implement the new process on a single pilot unit"},{"l":"C","c":false,"t":"Check — analyze baseline hand-off data from the previous year"},{"l":"D","c":false,"t":"Act — standardize the process across all units"}],"rat":"In PDCA (Plan-Do-Check-Act), after the Plan phase, the Do phase implements the change on a small scale (pilot) to test the hypothesis before broader rollout."},
{"id":"RW-D3-48","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.8","stem":"A hospital implements a new sepsis early-warning system at a cost of $200K. Twelve months later, sepsis-related ICU admissions dropped by 30, each avoided case saving approximately $15,000 in costs. What is the first-year ROI?","opts":[{"l":"A","c":false,"t":"30%"},{"l":"B","c":true,"t":"125%"},{"l":"C","c":false,"t":"15%"},{"l":"D","c":false,"t":"200%"}],"rat":"Net benefit = (30 × $15,000) − $200,000 = $450,000 − $200,000 = $250,000. ROI = ($250,000 ÷ $200,000) × 100 = 125%."},
{"id":"RW-D3-49","domain":2,"cog":"AN","correct":"B","task":"Task 3.A.7, 3.A.8","stem":"An IT team proposes a $1.8M clinical analytics platform with a projected $3.2M in efficiency gains and quality-related revenue improvements over 3 years. The CFO asks whether this investment should be approved given the organization&#x27;s current strategic priorities. The MOST appropriate response from the informatics director is to:","opts":[{"l":"A","c":false,"t":"Present the ROI of 78% and recommend immediate approval"},{"l":"B","c":true,"t":"Present the financial case alongside strategic alignment evidence and risk analysis"},{"l":"C","c":false,"t":"Ask the vendor to lower the price before presenting to leadership"},{"l":"D","c":false,"t":"Defer to the CFO&#x27;s judgment without providing analysis"}],"rat":"A complete business case includes ROI AND strategic alignment, risks, and assumptions — presenting financials alone is insufficient for executive decision-making."},
{"id":"RW-D3-50","domain":2,"cog":"AP","correct":"B","task":"Task 3.B.2","stem":"A hospital must meet CMS Conditions of Participation (CoP) requirements to receive Medicare and Medicaid reimbursement. Which system-related activity is MOST directly driven by this requirement?","opts":[{"l":"A","c":false,"t":"Purchasing a new PACS system for radiology"},{"l":"B","c":true,"t":"Ensuring clinical information systems support required documentation standards and patient rights processes"},{"l":"C","c":false,"t":"Negotiating SLAs with the EHR vendor"},{"l":"D","c":false,"t":"Implementing a SIEM platform"}],"rat":"CMS Conditions of Participation are regulatory requirements that hospitals must meet for Medicare/Medicaid reimbursement — they drive documentation, care quality, and patient rights requirements in clinical systems."},
{"id":"RW-D3-51","domain":2,"cog":"AN","correct":"B","task":"Task 3.B.5","stem":"A CIO reads that an AI-powered diagnostic imaging tool has generated significant vendor hype but has limited peer-reviewed evidence of clinical efficacy. The vendor claims &quot;this technology will transform radiology within 2 years.&quot; Before committing to a purchase, the MOST appropriate assessment framework is:","opts":[{"l":"A","c":false,"t":"DMAIC analysis of current radiology productivity"},{"l":"B","c":true,"t":"The Gartner Hype Cycle — to assess the technology&#x27;s actual maturity vs. its current hype level"},{"l":"C","c":false,"t":"A SWOT analysis of the vendor&#x27;s market position"},{"l":"D","c":false,"t":"An RFP with no further due diligence"}],"rat":"The Gartner Hype Cycle maps technologies across stages from peak hype to plateau of productivity, helping organizations assess readiness for enterprise adoption versus early-adopter risk."},
{"id":"RW-D3-52","domain":2,"cog":"AP","correct":"B","task":"Task 3.B.5","stem":"Before committing to an enterprise-wide deployment of a new AI clinical documentation tool, the informatics team runs a structured, time-limited trial in one unit with defined success metrics and an exit plan if results are unsatisfactory. This approach is called:","opts":[{"l":"A","c":false,"t":"UAT"},{"l":"B","c":true,"t":"Proof of concept (POC) / pilot"},{"l":"C","c":false,"t":"Integration testing"},{"l":"D","c":false,"t":"Reference site visit"}],"rat":"A proof of concept or pilot tests an emerging or unproven technology in a controlled setting before committing to enterprise investment, reducing the risk of large-scale failure."},
{"id":"RW-D3-53","domain":2,"cog":"AP","correct":"B","task":"Task 3.B.6","stem":"A health system&#x27;s EHR, scheduling system, and claims database each store provider information, but provider names, NPIs, and specialties are inconsistent across systems, causing reporting errors. The MOST appropriate governance solution is:","opts":[{"l":"A","c":false,"t":"Retrain data entry staff in each department"},{"l":"B","c":true,"t":"Implement a master data management (MDM) program with a single authoritative provider data source"},{"l":"C","c":false,"t":"Export all provider data to a spreadsheet monthly for manual reconciliation"},{"l":"D","c":false,"t":"Assign each system a separate data dictionary"}],"rat":"MDM ensures that shared data entities (providers, patients, facilities) have a single authoritative source and consistent representation across all systems."},
{"id":"RW-D3-54","domain":2,"cog":"AP","correct":"B","task":"Task 3.B.6","stem":"A hospital&#x27;s data governance program assigns specific individuals accountability for the accuracy, completeness, and consistency of data within their functional domain — for example, one person owns lab result data quality and another owns medication data quality. These individuals are called:","opts":[{"l":"A","c":false,"t":"Data architects"},{"l":"B","c":true,"t":"Data stewards"},{"l":"C","c":false,"t":"CISO representatives"},{"l":"D","c":false,"t":"Business intelligence analysts"}],"rat":"Data stewards are domain-level accountable owners for data quality, definitions, and standards — a core role in a data governance program."},
{"id":"RW-D3-55","domain":2,"cog":"AP","correct":"C","task":"Task 3.C.3","stem":"During an EHR go-live week, informatics specialists are stationed on each nursing unit throughout all shifts, walking alongside nurses and answering questions immediately at the point of care. This support model is called:","opts":[{"l":"A","c":false,"t":"Train-the-Trainer"},{"l":"B","c":false,"t":"Computer-based learning"},{"l":"C","c":true,"t":"At-the-Elbow (ATE) support"},{"l":"D","c":false,"t":"Superuser model"}],"rat":"At-the-Elbow support deploys implementation specialists directly at the point of care during go-live to provide real-time, workflow-embedded assistance."},
{"id":"RW-D3-56","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.3","stem":"After go-live, a health system designates one highly proficient EHR user per unit to serve as a peer resource — answering colleagues&#x27; questions, reporting recurring issues to the informatics team, and providing ongoing optimization input. This role is called:","opts":[{"l":"A","c":false,"t":"At-the-Elbow specialist"},{"l":"B","c":true,"t":"Superuser"},{"l":"C","c":false,"t":"Train-the-Trainer coordinator"},{"l":"D","c":false,"t":"Help Desk Tier 1"}],"rat":"Superusers are empowered end-users who serve as peer support, optimization feedback channels, and system change champions after go-live — distinct from ATE specialists who are temporary implementation staff."},
{"id":"RW-D3-57","domain":2,"cog":"RE","correct":"C","task":"Task 3.C.3","stem":"A hospital deploys pre-recorded EHR training modules that nurses complete on their own schedule before go-live. This training delivery method is BEST described as:","opts":[{"l":"A","c":false,"t":"At-the-Elbow support"},{"l":"B","c":false,"t":"Train-the-Trainer"},{"l":"C","c":true,"t":"Computer-Based Learning (CBL) / eLearning"},{"l":"D","c":false,"t":"Classroom training"}],"rat":"CBL/eLearning is self-paced, asynchronous, and scalable — nurses complete it independently. It reduces scheduling conflicts but lacks real-time feedback compared to classroom training."},
{"id":"RW-D3-58","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.5","stem":"An IT operations team receives notification from the EHR vendor that a critical security patch addressing a known vulnerability must be applied within 30 days. The team should:","opts":[{"l":"A","c":false,"t":"Apply the patch immediately to production without testing"},{"l":"B","c":true,"t":"Evaluate, test in a non-production environment, schedule through change control, and deploy within the required window"},{"l":"C","c":false,"t":"Defer the patch until the next planned major upgrade"},{"l":"D","c":false,"t":"Notify clinical staff and let them decide whether to apply the patch"}],"rat":"Patch management requires testing before production deployment and formal change control approval — but critical security patches must be applied within vendor-recommended or regulatory timeframes."},
{"id":"RW-D3-59","domain":2,"cog":"AN","correct":"B","task":"Task 3.C.6","stem":"Help desk ticket data shows a 3-fold increase in password reset requests over the past two weeks, all from the same clinical application. Tickets also note that the application began displaying a new login screen after a recent update. The MOST likely root cause is:","opts":[{"l":"A","c":false,"t":"A widespread phishing attack on clinical staff"},{"l":"B","c":true,"t":"The recent software update changed the login process, causing user confusion"},{"l":"C","c":false,"t":"A database corruption issue in the password management system"},{"l":"D","c":false,"t":"Inadequate password complexity requirements"}],"rat":"Trend analysis of help desk tickets — especially tickets correlated with a recent system change — is the most efficient first step in identifying operational root causes before escalating to security."},
{"id":"RW-D3-60","domain":2,"cog":"AP","correct":"B","task":"Task 3.D.2","stem":"During EHR testing, a developer makes an unauthorized configuration change directly in the test environment to &quot;fix&quot; a screen layout. The testing team discovers the change was not documented or approved. Which internal control was violated?","opts":[{"l":"A","c":false,"t":"Physical security of the test server"},{"l":"B","c":true,"t":"Change control / versioning control in the test environment"},{"l":"C","c":false,"t":"Data encryption policy"},{"l":"D","c":false,"t":"User acceptance testing protocol"}],"rat":"Even in test environments, all configuration changes must go through change control and versioning to ensure test results are valid and the system state is known and reproducible."},
{"id":"RW-D3-61","domain":2,"cog":"AP","correct":"C","task":"Task 3.D.3","stem":"After completing UAT, the project team and organizational leadership formally sign a document confirming that the delivered system meets all requirements defined in the Statement of Work, and that the vendor has fulfilled its contractual obligations. This activity is called:","opts":[{"l":"A","c":false,"t":"Integration testing"},{"l":"B","c":false,"t":"Regression testing"},{"l":"C","c":true,"t":"Acceptance testing / formal sign-off"},{"l":"D","c":false,"t":"Benefits realization review"}],"rat":"Acceptance testing produces the formal contractual sign-off that delivered functionality matches the SOW specifications — distinct from UAT, which validates clinical workflow fit."},
{"id":"RW-D3-62","domain":2,"cog":"AP","correct":"B","task":"Task 3.E.1","stem":"A systems administrator discovers that audit log records in the EHR have been altered — timestamps removed and certain access events deleted — apparently to conceal unauthorized record access. Which component of the CIA triad was violated?","opts":[{"l":"A","c":false,"t":"Confidentiality"},{"l":"B","c":true,"t":"Integrity"},{"l":"C","c":false,"t":"Availability"},{"l":"D","c":false,"t":"Authentication"}],"rat":"Integrity means data is accurate, complete, and has not been improperly altered. Tampering with audit logs violates data integrity."},
{"id":"RW-D3-63","domain":2,"cog":"AP","correct":"C","task":"Task 3.E.3","stem":"A hospital conducts a quarterly review of all user accounts in the EHR to verify that each account&#x27;s access permissions still match the user&#x27;s current job role. Accounts that have excessive or stale access are corrected. This process is called:","opts":[{"l":"A","c":false,"t":"Penetration testing"},{"l":"B","c":false,"t":"Privilege escalation review"},{"l":"C","c":true,"t":"Access recertification / periodic access review"},{"l":"D","c":false,"t":"Onboarding validation"}],"rat":"Periodic access recertification (also called access review) ensures that user permissions remain aligned with current job responsibilities — removing access granted for old roles that was never revoked."},
{"id":"RW-D3-64","domain":2,"cog":"RE","correct":"C","task":"Task 3.E.4","stem":"A hospital installs badge-access-only entry to its server room, installs a surveillance camera at the entrance, and requires visitors to sign a physical log. These measures are examples of:","opts":[{"l":"A","c":false,"t":"Technical safeguards"},{"l":"B","c":false,"t":"Administrative safeguards"},{"l":"C","c":true,"t":"Physical safeguards"},{"l":"D","c":false,"t":"Operational controls"}],"rat":"Physical safeguards control physical access to facilities and equipment containing ePHI — including locked server rooms, badge access, surveillance cameras, and visitor logs."},
{"id":"RW-D3-65","domain":2,"cog":"AP","correct":"B","task":"Task 3.E.5","stem":"A patient files a complaint that their behavioral health records were shared with their employer without consent. The hospital&#x27;s clinical informatics director determines this is a potential HIPAA Privacy Rule violation. Which organizational role is the PRIMARY owner of the investigation and response?","opts":[{"l":"A","c":false,"t":"CISO (Chief Information Security Officer)"},{"l":"B","c":true,"t":"Privacy Officer"},{"l":"C","c":false,"t":"Compliance Officer"},{"l":"D","c":false,"t":"IT Help Desk Manager"}],"rat":"The Privacy Officer is responsible for HIPAA Privacy Rule compliance, PHI disclosure policies, and breach investigation and response. The CISO handles security (ePHI technical controls); they often collaborate but the Privacy Officer leads privacy complaints."},
{"id":"RW-D3-66","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.1","stem":"A hospital&#x27;s IT steering committee receives a proposal to implement a new AI-powered nursing documentation assistant. Before authorizing the project, the committee wants to know whether it is technically achievable, financially viable, and organizationally supportable. This initial evaluation is called:","opts":[{"l":"A","c":false,"t":"Gap analysis"},{"l":"B","c":true,"t":"Feasibility study"},{"l":"C","c":false,"t":"Needs assessment only"},{"l":"D","c":false,"t":"Cost-benefit analysis"}],"rat":"A feasibility study evaluates whether a proposed project is technically feasible, financially viable, legally permissible, and organizationally supportable before committing planning resources. It is the primary output of the SDLC Planning phase before the project charter is authorized."},
{"id":"RW-D3-67","domain":2,"cog":"RE","correct":"C","task":"Task 3.A.1","stem":"A project team has received formal project charter approval and documented scope, objectives, budget, and sponsor. They are now interviewing clinical end users to document what the system must do and what performance standards it must meet. Which SDLC phase are they in?","opts":[{"l":"A","c":false,"t":"Design"},{"l":"B","c":false,"t":"Testing"},{"l":"C","c":true,"t":"Analysis / Requirements"},{"l":"D","c":false,"t":"Implementation"}],"rat":"After Planning (project charter), the Analysis/Requirements phase gathers and documents functional requirements (what the system must do) and non-functional requirements (performance, availability, security) from stakeholders before any design begins."},
{"id":"RW-D3-68","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.1, 3.A.2","stem":"During requirements gathering for a new scheduling system, the team documents: (1) the ability to book appointments in real time, (2) all screens must respond in under 3 seconds, and (3) the system must achieve 99.9% monthly availability. How should these be categorized?","opts":[{"l":"A","c":false,"t":"All three are functional requirements"},{"l":"B","c":true,"t":"Real-time booking is functional; 3-second response time and 99.9% availability are non-functional requirements"},{"l":"C","c":false,"t":"All three are non-functional requirements"},{"l":"D","c":false,"t":"99.9% availability is functional; the others are non-functional"}],"rat":"Functional requirements define what the system does (book appointments in real time). Non-functional requirements define how well it performs — response time, availability, security, and scalability are quality attributes, not features."},
{"id":"RW-D3-69","domain":2,"cog":"AP","correct":"C","task":"Task 3.A.1","stem":"After requirements gathering, the project team produces technical specifications, interface design documents, future-state workflow diagrams, database schema, and a training plan outline. These artifacts are outputs of which SDLC phase?","opts":[{"l":"A","c":false,"t":"Analysis"},{"l":"B","c":false,"t":"Testing"},{"l":"C","c":true,"t":"Design"},{"l":"D","c":false,"t":"Maintenance"}],"rat":"The Design phase transforms requirements into technical blueprints — system architecture, interface specifications, future-state workflows, data models, and the training plan outline — all produced before any build or configuration begins."},
{"id":"RW-D3-70","domain":2,"cog":"AN","correct":"B","task":"Task 3.A.1","stem":"A hospital implements a commercial EHR by activating standard modules, configuring workflow settings, and building order sets within the vendor&#x27;s configuration tools — without writing any original code. A separate organization builds a proprietary patient portal from scratch using its own development team. Which statement BEST describes these two approaches?","opts":[{"l":"A","c":false,"t":"Both are performing custom development"},{"l":"B","c":true,"t":"The first is configuring a commercial system; the second is performing custom development"},{"l":"C","c":false,"t":"Both are configuring vendor products"},{"l":"D","c":false,"t":"The first built a custom interface; the second used a vendor portal"}],"rat":"Configuration = activating and customizing features within a vendor&#x27;s existing platform without writing original code. Custom development = building original software from scratch. Most EHR implementations are configuration projects, not development projects — a key distinction on scope, risk, and skills required."},
{"id":"RW-D3-71","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.1, 3.D.2","stem":"An analyst deploys a new CDS alert build directly to the production EHR environment to &quot;test it quickly&quot; — bypassing the test and UAT environments. Why is this a serious violation of systems lifecycle controls?","opts":[{"l":"A","c":false,"t":"It increases licensing costs for the additional environment usage"},{"l":"B","c":true,"t":"Testing in production risks exposing live patients to untested logic that could cause patient harm or clinical workflow disruption"},{"l":"C","c":false,"t":"It violates the SLA with the EHR vendor"},{"l":"D","c":false,"t":"It requires additional project charter approval from leadership"}],"rat":"Production environments contain live patient data and active clinical workflows. All testing must occur in isolated non-production environments (development → test → UAT → production) to prevent untested logic from harming patients or disrupting care."},
{"id":"RW-D3-72","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.1, 3.C.2","stem":"A health system plans its EHR go-live with two options: (1) go live across all 6 hospitals simultaneously (&quot;big bang&quot;) or (2) go live at one facility per quarter over 18 months (&quot;phased&quot;). Which statement BEST describes the primary trade-off?","opts":[{"l":"A","c":false,"t":"Big bang reduces overall project risk; phased rollout increases risk"},{"l":"B","c":true,"t":"Phased rollout reduces per-event risk and allows lessons learned, but requires managing dual environments longer; big bang eliminates dual-environment complexity but concentrates all risk at one moment"},{"l":"C","c":false,"t":"Both approaches have identical risk profiles"},{"l":"D","c":false,"t":"Phased rollout is always preferred regardless of organizational context"}],"rat":"Phased rollout reduces the blast radius of go-live issues and generates learnings for subsequent sites, but requires running old and new systems in parallel. Big bang is faster and eliminates dual-environment complexity but concentrates all implementation risk into a single high-stakes event."},
{"id":"RW-D3-73","domain":2,"cog":"AP","correct":"C","task":"Task 3.A.1","stem":"During a revenue cycle system go-live, the team operates both the old and new systems simultaneously for 30 days — processing all transactions in both and comparing outputs before decommissioning the old system. This cutover strategy is called:","opts":[{"l":"A","c":false,"t":"Big bang cutover"},{"l":"B","c":false,"t":"Phased rollout"},{"l":"C","c":true,"t":"Parallel run"},{"l":"D","c":false,"t":"Pilot deployment"}],"rat":"A parallel run operates old and new systems simultaneously, validating new system output against the established system before full cutover. It reduces risk but doubles operational workload during the overlap period."},
{"id":"RW-D3-74","domain":2,"cog":"AP","correct":"C","task":"Task 3.A.1","stem":"Three months after an EHR go-live, the informatics team analyzes help desk ticket trends, physician satisfaction scores, and documentation completeness data to identify top enhancement priorities. This activity belongs to which SDLC phase?","opts":[{"l":"A","c":false,"t":"Analysis / Requirements"},{"l":"B","c":false,"t":"Testing"},{"l":"C","c":true,"t":"Maintenance / Optimization"},{"l":"D","c":false,"t":"Design"}],"rat":"The Maintenance/Optimization phase (post-go-live) includes ongoing performance monitoring, user feedback collection, issue resolution, and enhancement planning — the final and continuous phase of the SDLC."},
{"id":"RW-D3-75","domain":2,"cog":"AN","correct":"C","task":"Task 3.A.1","stem":"A hospital is planning a new AI-powered clinical decision support platform. Requirements are unclear, the technology is novel, and there is significant risk of technical failure. Which SDLC model BEST accommodates this high-uncertainty, risk-driven situation?","opts":[{"l":"A","c":false,"t":"Waterfall — requirements must be locked before build begins"},{"l":"B","c":false,"t":"Agile — iterative sprints with continuous user feedback"},{"l":"C","c":true,"t":"Spiral — explicitly designed for risk-driven iteration with repeated risk assessment cycles"},{"l":"D","c":false,"t":"RAD — fast prototyping for quick delivery"}],"rat":"The Spiral SDLC model incorporates explicit risk assessment at every iteration — ideal for projects with high uncertainty, novel technology, or significant failure risk where requirements cannot be defined upfront."},
{"id":"RW-D3-76","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.1, 3.C.2","stem":"A team is migrating 10 years of patient records from a legacy EHR to a new system. They must map legacy data fields to the new schema, cleanse data quality issues, and validate record completeness after migration. What is the PRIMARY patient safety risk if data migration is not executed carefully?","opts":[{"l":"A","c":false,"t":"Users will reject the new system due to unfamiliar screens"},{"l":"B","c":true,"t":"Incomplete or inaccurate patient records in the new system could lead to clinical errors and patient harm"},{"l":"C","c":false,"t":"Storage costs will exceed the project budget"},{"l":"D","c":false,"t":"Requirements will be missed during the analysis phase"}],"rat":"Data migration errors can result in missing allergies, incomplete medication histories, or incorrect problem lists in the new system — creating direct patient safety risks. Data migration validation is a critical lifecycle activity, not merely a technical task."},
{"id":"RW-D3-77","domain":2,"cog":"RE","correct":"B","task":"Task 3.A.1, 3.C.2","stem":"A hospital deploys a major EHR upgrade on a Saturday night. The deployment plan includes documented steps, responsible parties, and decision criteria for reverting to the previous system version if critical issues are discovered after go-live. What is this document called?","opts":[{"l":"A","c":false,"t":"Training plan"},{"l":"B","c":true,"t":"Rollback plan"},{"l":"C","c":false,"t":"Post-implementation review template"},{"l":"D","c":false,"t":"Vendor patch schedule"}],"rat":"A rollback plan documents the specific steps to revert to the prior system state if a deployment fails — including who makes the rollback decision, when, and how. It is an essential risk management artifact for any production deployment."},
{"id":"RW-D3-78","domain":2,"cog":"AP","correct":"B","task":"Task 3.A.1, 3.B.6, 3.E.6","stem":"A health system is retiring a legacy laboratory system after migrating active data to the new LIS. Before decommissioning, which activities are MOST critical from compliance and data governance perspectives?","opts":[{"l":"A","c":false,"t":"Shutting down the server immediately after migration is confirmed"},{"l":"B","c":true,"t":"Verifying migration completeness, establishing an archival access plan for historical records, and disposing of the legacy system per the data retention and destruction policy"},{"l":"C","c":false,"t":"Deleting all legacy data immediately to reduce storage costs"},{"l":"D","c":false,"t":"Returning the hardware to the original vendor without data erasure"}],"rat":"System decommissioning requires: confirming all needed data migrated successfully, establishing how legacy records will be accessed during the retention period, and disposing of hardware per NIST 800-88 and organizational data lifecycle policy."},
{"id":"RW-D3-79","domain":2,"cog":"RE","correct":"B","task":"Task 3.C.2","stem":"An IT change management team categorizes three upcoming changes: (1) a monthly security patch following a fully documented, pre-approved repeatable process; (2) a new CDS alert configuration requiring full CAB impact review; and (3) a hotfix needed immediately to correct a patient safety error in production. These represent which change types respectively?","opts":[{"l":"A","c":false,"t":"Normal, emergency, standard"},{"l":"B","c":true,"t":"Standard, normal, emergency"},{"l":"C","c":false,"t":"Emergency, standard, normal"},{"l":"D","c":false,"t":"All three require full CAB review before deployment"}],"rat":"Standard = pre-approved, low-risk, repeatable (monthly patch); Normal = assessed and approved by CAB (new CDS configuration); Emergency = urgent patient safety fix bypassing normal timelines with expedited authorization and retroactive review."},
{"id":"RW-D3-80","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.2","stem":"A critical bug in the EHR&#x27;s medication dosing module is causing incorrect dose calculations for pediatric patients. The IS team has a fix ready but no CAB meeting is scheduled for 5 days. What is the correct process?","opts":[{"l":"A","c":false,"t":"Wait 5 days for the next scheduled CAB meeting before deploying"},{"l":"B","c":true,"t":"Invoke the emergency change process — deploy with expedited authorization, document thoroughly, and complete formal retrospective review after deployment"},{"l":"C","c":false,"t":"Ask nurses to manually double-check all pediatric doses until the next CAB meeting"},{"l":"D","c":false,"t":"Roll back the entire EHR to the previous version without authorization"}],"rat":"Emergency changes bypass normal CAB timelines due to urgent patient safety risk but require expedited authorization (not informal approval), thorough documentation, and a retroactive formal review after deployment."},
{"id":"RW-D3-81","domain":2,"cog":"AN","correct":"B","task":"Task 3.C.2","stem":"A hospital&#x27;s change management policy prohibits all non-emergency system changes from December 20 to January 5 due to peak holiday census and fiscal year-end reporting. An analyst wants to deploy a new scheduling enhancement on December 22. What should happen?","opts":[{"l":"A","c":false,"t":"Deploy it because it is a low-risk change"},{"l":"B","c":true,"t":"The change falls within the blackout period and must be deferred to after January 5 unless it meets the organization&#x27;s emergency threshold"},{"l":"C","c":false,"t":"Request a waiver from the EHR vendor"},{"l":"D","c":false,"t":"Obtain informal permission from the department manager and proceed"}],"rat":"Change freeze / blackout periods protect high-risk operational windows from non-critical system changes. Policy must be enforced consistently — only genuine emergencies proceed during a freeze, and they require explicit executive authorization."},
{"id":"RW-D3-82","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.2","stem":"An informatics team has 8 approved EHR configuration changes — 3 alert updates, 2 order set revisions, and 3 report modifications — all ready for deployment. Rather than scheduling 8 separate maintenance windows, the team packages them into a single scheduled deployment event. This practice is called:","opts":[{"l":"A","c":false,"t":"Emergency change management"},{"l":"B","c":true,"t":"Release management"},{"l":"C","c":false,"t":"Post-implementation review"},{"l":"D","c":false,"t":"Configuration drift correction"}],"rat":"Release management packages multiple approved changes into a single deployment event — reducing maintenance windows, managing inter-change dependencies, and minimizing cumulative disruption to clinical operations."},
{"id":"RW-D3-83","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.2","stem":"Before deploying a new clinical alert to the EHR&#x27;s medication ordering module, the change management team asks: &quot;Which downstream systems receive medication order data, which clinical workflows will be affected, and what is the rollback plan if issues arise?&quot; This pre-deployment activity is called:","opts":[{"l":"A","c":false,"t":"Post-implementation review"},{"l":"B","c":true,"t":"Change impact assessment"},{"l":"C","c":false,"t":"Benefits realization review"},{"l":"D","c":false,"t":"Regression testing"}],"rat":"A change impact assessment evaluates which systems, workflows, and users will be affected by a proposed change before the CAB approves it — ensuring risks are understood and mitigation plans are in place before deployment."},
{"id":"RW-D3-84","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.2","stem":"One week after a major EHR upgrade deployment, the IT team reviews what went as planned, what caused the unplanned 45-minute downtime during the maintenance window, what the root cause was, and what should be changed in the next deployment process. This structured retrospective is called:","opts":[{"l":"A","c":false,"t":"Benefits realization evaluation"},{"l":"B","c":true,"t":"Post-implementation review (PIR)"},{"l":"C","c":false,"t":"Change Advisory Board meeting"},{"l":"D","c":false,"t":"User acceptance testing retrospective"}],"rat":"A Post-Implementation Review (PIR) evaluates a system change after deployment — identifying what succeeded, what failed, root causes of issues, and lessons learned to improve future change management processes."},
{"id":"RW-D3-85","domain":2,"cog":"AN","correct":"B","task":"Task 3.C.2","stem":"An IS analyst discovers that the production EHR has 47 configuration settings that differ from the documented, CAB-approved baseline — most were made informally by developers bypassing change control. This situation is called:","opts":[{"l":"A","c":false,"t":"Version conflict"},{"l":"B","c":true,"t":"Configuration drift"},{"l":"C","c":false,"t":"Scope creep"},{"l":"D","c":false,"t":"System degradation"}],"rat":"Configuration drift occurs when a production system&#x27;s actual state diverges from its documented, approved baseline — typically due to informal changes bypassing change control. It creates unpredictability, audit failures, and difficult troubleshooting."},
{"id":"RW-D3-86","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.2","stem":"The IS team is scheduling a 4-hour EHR maintenance window for Saturday 2–6 AM. Which action regarding end-user communication is MOST important before the deployment?","opts":[{"l":"A","c":false,"t":"Notify only the IS team; clinical staff will discover the downtime when they attempt to log in"},{"l":"B","c":true,"t":"Notify all affected clinical staff, department managers, and on-call providers in advance with the downtime window, affected systems, and downtime procedure instructions"},{"l":"C","c":false,"t":"Only the CIO needs to approve; end-user notification is optional for planned maintenance"},{"l":"D","c":false,"t":"Notification is only required for unplanned outages, not planned maintenance windows"}],"rat":"Planned system changes require proactive communication to all affected users — including the exact downtime window, which systems are affected, and how to access downtime procedures — to ensure clinical continuity and prevent patient safety gaps."},
{"id":"RW-D3-87","domain":2,"cog":"AN","correct":"C","task":"Task 3.C.2, 3.D.1","stem":"An IS team deploys a routine upgrade to the EHR overnight. The next morning, the pharmacy team reports that medication dispense records are no longer flowing from the pharmacy system to the eMAR. The issue was not present before the upgrade. Which type of testing, if performed properly, should have caught this issue before production deployment?","opts":[{"l":"A","c":false,"t":"Unit testing — testing the upgrade module in isolation"},{"l":"B","c":false,"t":"Stress testing — testing under high user load"},{"l":"C","c":true,"t":"Regression testing — verifying existing integrations were not broken by the new change"},{"l":"D","c":false,"t":"UAT — clinical staff validating new features"}],"rat":"Regression testing specifically verifies that new code or configuration changes did not break previously working functionality — including cross-system integrations like pharmacy-to-eMAR data flow. It is the primary test type to catch unintended consequences of upgrades."},
{"id":"RW-D3-88","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.2","stem":"A health system&#x27;s change management policy states that all changes must be categorized, documented, approved by the appropriate authority level, tested in non-production, scheduled during approved maintenance windows, and reviewed post-deployment. Which principle does this policy embody?","opts":[{"l":"A","c":false,"t":"Release management consolidation"},{"l":"B","c":true,"t":"Structured, controlled change management to protect system stability and clinical safety"},{"l":"C","c":false,"t":"Agile sprint governance"},{"l":"D","c":false,"t":"Vendor SLA compliance management"}],"rat":"Structured change management policies protect production environments from uncontrolled modifications — ensuring all changes are assessed, approved, tested, and reviewed to minimize risk to system stability and patient safety."},
{"id":"RW-D3-89","domain":2,"cog":"AN","correct":"B","task":"Task 3.C.2, 3.D.2","stem":"An analyst notices that the EHR&#x27;s test environment has not been refreshed with production data in 8 months. Testers are validating a new workflow against 8-month-old data patterns that no longer represent current clinical practice. What is the PRIMARY risk of this situation?","opts":[{"l":"A","c":false,"t":"Testing will take longer than planned"},{"l":"B","c":true,"t":"Test results may not reflect real-world behavior, leading to issues discovered in production after go-live"},{"l":"C","c":false,"t":"The test environment will run out of storage"},{"l":"D","c":false,"t":"Testers will not follow the test scripts correctly"}],"rat":"Test environments should be periodically refreshed with anonymized production data to ensure testing reflects current real-world data patterns. Stale test data produces false confidence — issues that only appear with current data volumes and configurations will be missed."},
{"id":"RW-D3-90","domain":2,"cog":"AP","correct":"B","task":"Task 3.C.2","stem":"A hospital&#x27;s change advisory board approves a major EHR configuration change scheduled for next Friday. On Thursday evening, the vendor releases a critical security patch that affects the same module. The IS team determines both changes cannot be deployed simultaneously without risk of conflict. What is the BEST action?","opts":[{"l":"A","c":false,"t":"Deploy both changes Friday as originally planned and troubleshoot any conflicts after the fact"},{"l":"B","c":true,"t":"Return both changes to the CAB for re-evaluation, reassess risk and scheduling, and deploy in the correct sequence"},{"l":"C","c":false,"t":"Cancel the security patch deployment since the configuration change was approved first"},{"l":"D","c":false,"t":"Deploy the configuration change Friday and schedule the security patch for the following week without CAB review"}],"rat":"When new information (conflicting changes) emerges after CAB approval, the changes must be returned to CAB for re-evaluation. Proceeding without re-assessment risks simultaneous deployment conflicts and unpredictable system behavior."}
];
